import React, { useEffect, useState } from "react";
import { supabase } from "../supabaseClient";
import { LogOut, RefreshCcw, User, MapPin, Clock, Phone, Smartphone, Car, Navigation } from "lucide-react";

const Dashboard = ({ session }) => {
  const [rides, setRides] = useState([]);
  const [isRefreshing, setIsRefreshing] = useState(false);

  useEffect(() => {
    fetchRides();

    const channel = supabase
      .channel('realtime-rides')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'rides' }, (payload) => {
        setRides((prev) => [payload.new, ...prev]);
      })
      .subscribe();

    return () => supabase.removeChannel(channel);
  }, []);

  const fetchRides = async () => {
    setIsRefreshing(true);
    const { data } = await supabase
      .from("rides")
      .select("*")
      .order("created_at", { ascending: false });
    setRides(data || []);
    setTimeout(() => setIsRefreshing(false), 600);
  };

  const handleLogout = () => supabase.auth.signOut();

  // --- Inline Styles ---
  const styles = {
    container: {
      minHeight: "100vh",
      background: "linear-gradient(135deg, #fdf2f5 0%, #fae1e8 100%)",
      fontFamily: "'Inter', sans-serif",
      padding: "20px",
      boxSizing: "border-box",
    },
    nav: {
      display: "flex",
      justifyContent: "space-between",
      alignItems: "center",
      background: "rgba(255, 255, 255, 0.7)",
      backdropFilter: "blur(10px)",
      padding: "15px 30px",
      borderRadius: "20px",
      marginBottom: "30px",
      boxShadow: "0 8px 32px rgba(229, 90, 123, 0.1)",
      border: "1px solid rgba(255, 255, 255, 0.3)",
    },
    brand: {
      fontSize: "24px",
      fontWeight: "800",
      color: "#e55a7b",
      margin: 0,
      display: "flex",
      alignItems: "center",
      gap: "10px",
    },
    adminInfo: {
      display: "flex",
      alignItems: "center",
      gap: "15px",
    },
    email: {
      color: "#636e72",
      fontSize: "14px",
      fontWeight: "500",
    },
    logoutBtn: {
      background: "#fff",
      border: "1px solid #e55a7b",
      color: "#e55a7b",
      padding: "8px 15px",
      borderRadius: "12px",
      cursor: "pointer",
      display: "flex",
      alignItems: "center",
      gap: "8px",
      fontWeight: "600",
      transition: "0.3s",
    },
    contentCard: {
      background: "rgba(255, 255, 255, 0.6)",
      backdropFilter: "blur(12px)",
      borderRadius: "24px",
      padding: "25px",
      boxShadow: "0 10px 40px rgba(0,0,0,0.03)",
      border: "1px solid rgba(255, 255, 255, 0.5)",
    },
    header: {
      display: "flex",
      justifyContent: "space-between",
      alignItems: "center",
      marginBottom: "20px",
    },
    tableWrapper: {
      overflowX: "auto",
    },
    table: {
      width: "100%",
      borderCollapse: "separate",
      borderSpacing: "0 10px",
    },
    th: {
      textAlign: "left",
      padding: "15px",
      color: "#636e72",
      fontSize: "14px",
      textTransform: "uppercase",
      letterSpacing: "1px",
    },
    tr: {
      background: "#fff",
      transition: "0.3s",
    },
    td: {
      padding: "15px",
      fontSize: "15px",
      color: "#2d3436",
    },
    passengerCell: {
      display: "flex",
      flexDirection: "column",
      gap: "4px",
    },
    locBox: {
      display: "flex",
      flexDirection: "column",
      gap: "6px",
      fontSize: "13px",
    },
    tag: {
      background: "#fdf2f5",
      color: "#e55a7b",
      padding: "4px 10px",
      borderRadius: "8px",
      fontSize: "12px",
      fontWeight: "700",
    }
  };

  return (
    <div style={styles.container}>
      {/* Navigation Bar */}
      <nav style={styles.nav}>
        <h1 style={styles.brand}><Navigation size={28} /> PAHEL Admin</h1>
        <div style={styles.adminInfo}>
          <span style={styles.email}>{session.user.email}</span>
          <button onClick={handleLogout} style={styles.logoutBtn}>
            <LogOut size={18} /> Logout
          </button>
        </div>
      </nav>

      <div style={styles.contentCard}>
        <div style={styles.header}>
          <h3 style={{ margin: 0, color: "#2d3436" }}>Live Bookings</h3>
          <button 
            onClick={fetchRides} 
            style={{
              ...styles.logoutBtn, 
              background: "#e55a7b", 
              color: "#fff",
              animation: isRefreshing ? "spin 1s linear infinite" : "none"
            }}
          >
            <RefreshCcw size={16} /> Refresh
          </button>
        </div>

        <div style={styles.tableWrapper}>
          <table style={styles.table}>
            <thead>
              <tr>
                <th style={styles.th}>Passenger & Contact</th>
                <th style={styles.th}>Route Details</th>
                <th style={styles.th}>Date & Time</th>
                <th style={styles.th}>Vehicle</th>
              </tr>
            </thead>
            <tbody>
              {rides.map((ride) => (
                <tr key={ride.id} style={styles.tr}>
                  <td style={{ ...styles.td, borderRadius: "15px 0 0 15px" }}>
                    <div style={styles.passengerCell}>
                      <span style={{ fontWeight: "700", color: "#e55a7b" }}>{ride.passenger_name}</span>
                      <div style={{ display: "flex", alignItems: "center", gap: "5px", fontSize: "13px" }}>
                        <Phone size={12} /> {ride.phone_number}
                      </div>
                      {ride.alt_phone && (
                        <div style={{ display: "flex", alignItems: "center", gap: "5px", fontSize: "12px", color: "#636e72" }}>
                          <Smartphone size={12} /> {ride.alt_phone}
                        </div>
                      )}
                    </div>
                  </td>
                  <td style={styles.td}>
                    <div style={styles.locBox}>
                      <div style={{ color: "#27ae60" }}><MapPin size={14} /> {ride.pickup_location}</div>
                      <div style={{ color: "#e74c3c" }}><MapPin size={14} /> {ride.drop_location}</div>
                    </div>
                  </td>
                  <td style={styles.td}>
                    <div style={{ fontSize: "13px" }}>
                      <Clock size={12} /> {ride.ride_date}<br/>
                      <strong>{ride.ride_time}</strong>
                    </div>
                  </td>
                  <td style={{ ...styles.td, borderRadius: "0 15px 15px 0" }}>
                    <span style={styles.tag}><Car size={12} /> {ride.vehicle_class}</span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {rides.length === 0 && (
            <div style={{ textAlign: "center", padding: "40px", color: "#636e72" }}>
              No bookings found yet.
            </div>
          )}
        </div>
      </div>

      <style>
        {`
          @keyframes spin { 100% { transform: rotate(360deg); } }
          tr:hover { transform: scale(1.01); box-shadow: 0 5px 15px rgba(0,0,0,0.05); }
        `}
      </style>
    </div>
  );
};

export default Dashboard;
